function formatProduct(product: { name: string; price: number; category?: string; inStock?: boolean }): string {
  const stock = product.inStock === false ? "Out of Stock" : "In Stock";
  const cat = product.category ? ` [${product.category}]` : "";
  return `${product.name}${cat} - $${product.price.toFixed(2)} (${stock})`;
}

console.log(formatProduct({ name: "Laptop", price: 999.99, category: "Electronics" }));
console.log(formatProduct({ name: "Book", price: 12.5 }));
console.log(formatProduct({ name: "Phone", price: 699, inStock: false }));

