function describeServer(config: { host: string; port: number; ssl?: { enabled: boolean; certPath: string } }): string {
  const protocol = config.ssl?.enabled ? "https" : "http";
  let result = `${protocol}://${config.host}:${config.port}`;
  if (config.ssl?.enabled) {
    result += ` (SSL: ${config.ssl.certPath})`;
  }
  return result;
}

console.log(describeServer({ host: "localhost", port: 3000 }));
console.log(describeServer({ host: "api.example.com", port: 443, ssl: { enabled: true, certPath: "/etc/ssl/cert.pem" } }));

