interface Todo {
  readonly id: number;
  title: string;
  completed: boolean;
  dueDate?: string;
}

function formatTodo(todo: Todo): string {
  const status = todo.completed ? "[x]" : "[ ]";
  const due = todo.dueDate ? ` (due: ${todo.dueDate})` : "";
  return `${status} #${todo.id}: ${todo.title}${due}`;
}

