exercises.solution:
interface WordCount {
  [word: string]: number;
}

function countWords(sentence: string): WordCount {
  const counts: WordCount = {};
  const words = sentence.split(" ");
  for (const word of words) {
    counts[word] = (counts[word] || 0) + 1;
  }
  return counts;
}

const result = countWords("the cat sat on the mat the cat");
console.log(`the: ${result["the"]}`);
console.log(`cat: ${result["cat"]}`);
console.log(`sat: ${result["sat"]}`);

