interface Vehicle {
  make: string;
  year: number;
}

interface Car extends Vehicle {
  doors: number;
}

interface Motorcycle extends Vehicle {
  engineCC: number;
}

function describeVehicle(vehicle: Car | Motorcycle): string {
  let desc = `${vehicle.year} ${vehicle.make}`;
  if ("doors" in vehicle) {
    desc += ` (${vehicle.doors}-door car)`;
  } else {
    desc += ` (${vehicle.engineCC}cc motorcycle)`;
  }
  return desc;
}

const car: Car = { make: "Toyota", year: 2024, doors: 4 };
const bike: Motorcycle = { make: "Harley", year: 2023, engineCC: 1200 };

console.log(describeVehicle(car));
console.log(describeVehicle(bike));

