exercises.solution:
interface BaseEvent {
  type: string;
  timestamp: string;
}

interface ClickEvent extends BaseEvent {
  type: "click";
  x: number;
  y: number;
}

interface KeyEvent extends BaseEvent {
  type: "key";
  key: string;
  ctrlKey: boolean;
}

function handleEvent(event: ClickEvent | KeyEvent): string {
  const base = `[${event.timestamp}]`;
  if (event.type === "click") {
    return `${base} Click at (${event.x}, ${event.y})`;
  }
  return `${base} Key: ${event.key} (ctrl: ${event.ctrlKey})`;
}

const click: ClickEvent = { type: "click", timestamp: "10:30:00", x: 100, y: 200 };
const key: KeyEvent = { type: "key", timestamp: "10:30:01", key: "Enter", ctrlKey: false };

console.log(handleEvent(click));
console.log(handleEvent(key));

