exercises.solution:
type NotificationType = "info" | "warning" | "error";

interface Notification {
  id: number;
  type: NotificationType;
  message: string;
  read: boolean;
}

function formatNotification(n: Notification): string {
  const icon = n.type === "error" ? "[!]" : n.type === "warning" ? "[~]" : "[i]";
  const status = n.read ? "read" : "unread";
  return `${icon} #${n.id}: ${n.message} (${status})`;
}

const notifications: Notification[] = [
  { id: 1, type: "info", message: "Welcome!", read: false },
  { id: 2, type: "error", message: "Disk full", read: true },
  { id: 3, type: "warning", message: "Low memory", read: false }
];

notifications.forEach(n => console.log(formatNotification(n)));

