exercises.solution:
interface ApiRequest {
  url: string;
  method: string;
}

interface GetRequest extends ApiRequest {
  method: "GET";
}

interface PostRequest extends ApiRequest {
  method: "POST";
  body: string;
}

type Request = GetRequest | PostRequest;

function executeRequest(req: Request): string {
  if (req.method === "POST") {
    return `POST ${req.url} with body: ${req.body}`;
  }
  return `GET ${req.url}`;
}

const get: GetRequest = { url: "/api/users", method: "GET" };
const post: PostRequest = { url: "/api/users", method: "POST", body: '{"name":"Alice"}' };

console.log(executeRequest(get));
console.log(executeRequest(post));
